<?php
 namespace WPAICG\Chat\Utils; if (!defined('ABSPATH')) { exit; } class Utils { public static function aipkit_human_time_diff($from, $to = null) { if (!is_numeric($from)) { $from = strtotime($from . ' GMT'); } if ($to !== null && !is_numeric($to)) { $to = strtotime($to . ' GMT'); } if (!$from) { return __('Invalid date', 'gpt3-ai-content-generator'); } if ($to === null) { $diff = human_time_diff($from, current_time('timestamp', true)); } else { $diff = human_time_diff($from, $to); } return sprintf(__('%s ago', 'gpt3-ai-content-generator'), $diff); } public static function aipkit_clean_text_for_tts(string $text): string { $cleaned_text = wp_strip_all_tags($text); $cleaned_text = preg_replace('/!\[[^\]]*\]\([^)]+\)/', '', $cleaned_text); $cleaned_text = preg_replace('/\[([^\]]+)\]\([^)]+\)/', '$1', $cleaned_text); $cleaned_text = preg_replace('/```[\s\S]*?```/', '', $cleaned_text); $cleaned_text = preg_replace('/`([^`]+)`/', '$1', $cleaned_text); $cleaned_text = str_replace(['**', '__', '*', '_'], '', $cleaned_text); $cleaned_text = preg_replace('/^#+\s+/m', '', $cleaned_text); $cleaned_text = preg_replace('/^>\s*/m', '', $cleaned_text); $cleaned_text = preg_replace('/^(\s*(\*|\-|\+)\s+|\s*\d+\.\s+)/m', '', $cleaned_text); $cleaned_text = preg_replace('/^( *(\*|-|_)){3,} *$/m', '', $cleaned_text); $cleaned_text = str_replace(['[]()', '()'], '', $cleaned_text); $cleaned_text = preg_replace('/\b(https?|ftp|file):\/\/[-A-Z0-9+&@#\/%?=~_|!:,.;]*[-A-Z0-9+&@#\/%=~_|]/i', '', $cleaned_text); $emoji_pattern = '/(?:' . '[\x{1F300}-\x{1F5FF}]' . '|[\x{1F600}-\x{1F64F}]' . '|[\x{1F680}-\x{1F6FF}]' . '|[\x{2600}-\x{26FF}]' . '|[\x{2700}-\x{27BF}]' . '|[\x{1F900}-\x{1F9FF}]' . '|[\x{1FA70}-\x{1FAFF}]' . '|[\x{FE00}-\x{FE0F}]' . '|[\x{E0020}-\x{E007F}]' . ')+/u'; $cleaned_text = preg_replace($emoji_pattern, '', $cleaned_text); $cleaned_text = preg_replace('/\s+/', ' ', $cleaned_text); $cleaned_text = trim($cleaned_text); return $cleaned_text; } }